fn solve(edges: Vec<Vec<i64>>, online: Vec<bool>, k: i64) -> i64 {
    let n = online.len() as i64;
    let mut graph = std::collections::HashMap::new();

    for edge in edges {
        let u = edge[0];
        let v = edge[1];
        let cost = edge[2];
        graph.entry(u).or_insert_with(Vec::new).push((v, cost));
    }

    use std::collections::BinaryHeap;
    let mut max_heap = BinaryHeap::new();
    max_heap.push((-i64::MAX, 0, 0)); // Use negative for max-heap simulation

    let mut max_min_edge = -1;
    let mut visited = vec![false; n as usize];

    while let Some((min_edge_neg, node, total_cost)) = max_heap.pop() {
        let min_edge = -min_edge_neg;

        if node == n - 1 {
            return max_min_edge;
        }

        if visited[node as usize] {
            continue;
        }

        visited[node as usize] = true;

        if let Some(neighbors) = graph.get(&node) {
            for &(v, cost) in neighbors {
                if online[v as usize] {
                    let new_total_cost = total_cost + cost;
                    let new_min_edge = std::cmp::min(min_edge, cost);

                    if new_total_cost <= k {
                        max_heap.push((-new_min_edge, v, new_total_cost));
                        max_min_edge = std::cmp::max(max_min_edge, new_min_edge);
                    }
                }
            }
        }
    }

    max_min_edge
}
